"use client";

import * as React from "react";
import { createPortal } from "react-dom";
import { cn } from "@/lib/utils";
import { format, isPast } from "date-fns";
import {
  Popover,
  PopoverAnchor,
  PopoverTrigger,
} from "@/components/ui/popover";
import { EventDetailPopover } from "./event-detail-popover";
import { useCalendarPopoverBoundary } from "./calendar-popover-context";
import type {
  CalendarEvent,
  CalendarEventItemProps,
  EventColor,
} from "./week-view-types";
import { EventContextMenu } from "./event-context-menu";

export const eventColorStyles: Record<
  EventColor,
  {
    bg: string;
    bgHover: string;
    border: string;
    borderLine: string;
    text: string;
  }
> = {
  red: {
    bg: "bg-event-red-bg",
    bgHover: "hover:bg-event-red-bg/70",
    border: "bg-event-red-border",
    borderLine: "border-event-red-border",
    text: "text-event-red",
  },
  orange: {
    bg: "bg-event-orange-bg",
    bgHover: "hover:bg-event-orange-bg/70",
    border: "bg-event-orange-border",
    borderLine: "border-event-orange-border",
    text: "text-event-orange",
  },
  yellow: {
    bg: "bg-event-yellow-bg",
    bgHover: "hover:bg-event-yellow-bg/70",
    border: "bg-event-yellow-border",
    borderLine: "border-event-yellow-border",
    text: "text-event-yellow",
  },
  green: {
    bg: "bg-event-green-bg",
    bgHover: "hover:bg-event-green-bg/70",
    border: "bg-event-green-border",
    borderLine: "border-event-green-border",
    text: "text-event-green",
  },
  blue: {
    bg: "bg-event-blue-bg",
    bgHover: "hover:bg-event-blue-bg/70",
    border: "bg-event-blue-border",
    borderLine: "border-event-blue-border",
    text: "text-event-blue",
  },
  purple: {
    bg: "bg-event-purple-bg",
    bgHover: "hover:bg-event-purple-bg/70",
    border: "bg-event-purple-border",
    borderLine: "border-event-purple-border",
    text: "text-event-purple",
  },
  gray: {
    bg: "bg-event-gray-bg",
    bgHover: "hover:bg-event-gray-bg/70",
    border: "bg-event-gray-border",
    borderLine: "border-event-gray-border",
    text: "text-event-gray",
  },
};

/**
 * Formats time showing only minutes if not on the hour
 * e.g., "10" for 10:00, "2:45" for 2:45
 */
function formatTimeShort(date: Date): string {
  const minutes = date.getMinutes();
  if (minutes === 0) {
    return format(date, "h");
  }
  return format(date, "h:mm");
}

/**
 * Formats event time as a compact range like "10–11 AM" or "11 AM–2 PM"
 */
function formatEventTimeRange(event: CalendarEvent): string {
  const startTime = formatTimeShort(event.start);
  const endTime = formatTimeShort(event.end);
  const endPeriod = format(event.end, "a");
  const startPeriod = format(event.start, "a");

  // If same period (both AM or both PM), only show period at the end
  if (startPeriod === endPeriod) {
    return `${startTime}\u2013${endTime} ${endPeriod}`;
  }

  // Different periods, show both
  return `${startTime} ${startPeriod}\u2013${endTime} ${endPeriod}`;
}

function computeOverrideStyle(
  positionedEvent: CalendarEventItemProps["positionedEvent"],
  hourHeight: number,
  overrideStart: Date,
  overrideEnd: Date,
) {
  const startMinutes =
    overrideStart.getHours() * 60 + overrideStart.getMinutes();
  let endMinutes = overrideEnd.getHours() * 60 + overrideEnd.getMinutes();
  // If end is midnight and on a different day than start, treat as 1440 (end of day)
  if (endMinutes === 0 && overrideEnd.getDate() !== overrideStart.getDate()) {
    endMinutes = 1440;
  }
  const topPx = (startMinutes / 60) * hourHeight;
  const heightPx = ((endMinutes - startMinutes) / 60) * hourHeight;

  return {
    top: `${topPx}px`,
    height: `${heightPx}px`,
    left: `${positionedEvent.left}%`,
    width: `${positionedEvent.width}%`,
    minHeight: "20px",
  };
}

const RESIZE_HOTZONE_PX = 8;

export function CalendarEventItem({
  positionedEvent,
  hourHeight,
  isPast: isPastProp,
  isSelected,
  onClick,
  dragVariant = "default",
  overrideStart,
  overrideEnd,
  onDragMouseDown,
  onResizeMouseDown,
  onEventChange,
  cursorY,
  cursorX,
  fixedWidth,
  fixedHeight,
  onContextMenuOpenChange,
  isSidebarOpen,
  onDockToSidebar,
  onClosePopover,
  onPrevWeek,
  onNextWeek,
  className,
}: CalendarEventItemProps) {
  const { event, segmentPosition = "full" } = positionedEvent;
  const color = event.color ?? "blue";
  const styles = eventColorStyles[color];
  const eventIsPast = isPastProp ?? isPast(event.end);
  const { view, boundaryRight, headerBottom } = useCalendarPopoverBoundary();
  const isDayView = view === "day";

  /** Ref to the event button element, used to measure its viewport rect. */
  const eventRef = React.useRef<HTMLDivElement>(null);

  /**
   * Viewport-relative top & height of the event element.
   * Used to vertically align the day-view PopoverAnchor with the event
   * so the popover appears beside the event rather than at a fixed position.
   */
  const [anchorRect, setAnchorRect] = React.useState<{
    top: number;
    height: number;
  } | null>(null);

  const showPopover = isSelected && isSidebarOpen === false;

  // Measure the event element's viewport position when the popover opens in
  // day view. useLayoutEffect ensures the measurement happens before paint so
  // the PopoverAnchor is positioned correctly on first frame.
  React.useLayoutEffect(() => {
    if (!showPopover || !isDayView || !eventRef.current) {
      setAnchorRect(null);
      return;
    }
    const rect = eventRef.current.getBoundingClientRect();
    setAnchorRect({ top: rect.top, height: rect.height });
  }, [showPopover, isDayView]);

  const hasTopRounding =
    segmentPosition === "start" || segmentPosition === "full";
  const hasBottomRounding =
    segmentPosition === "end" || segmentPosition === "full";
  const showTopResize =
    segmentPosition === "start" || segmentPosition === "full";
  const showBottomResize =
    segmentPosition === "end" || segmentPosition === "full";

  const [contextMenu, setContextMenu] = React.useState<{
    x: number;
    y: number;
  } | null>(null);

  const closeContextMenu = React.useCallback(() => {
    setContextMenu(null);
    onContextMenuOpenChange?.(false);
  }, [onContextMenuOpenChange]);

  const displayStart = overrideStart ?? event.start;
  const displayEnd = overrideEnd ?? event.end;

  const displayEvent: CalendarEvent =
    overrideStart && overrideEnd
      ? { ...event, start: displayStart, end: displayEnd }
      : event;

  const defaultStyle = {
    top: `${positionedEvent.top}%`,
    height: `${positionedEvent.height}%`,
    left: `${positionedEvent.left}%`,
    width: `${positionedEvent.width}%`,
    minHeight: "20px",
    zIndex: isSelected ? 20 : positionedEvent.column,
  };

  const posStyle =
    overrideStart && overrideEnd
      ? computeOverrideStyle(
          positionedEvent,
          hourHeight,
          overrideStart,
          overrideEnd,
        )
      : defaultStyle;

  const heightInPixels =
    overrideStart && overrideEnd
      ? Number.parseFloat(String(posStyle.height))
      : (positionedEvent.height / 100) * 24 * hourHeight;
  const isCompact = heightInPixels < 40;

  if (dragVariant === "ghost") {
    return (
      <div
        className={cn(
          "absolute rounded-sm px-2 py-1 pointer-events-none opacity-30 overflow-hidden",
          className,
        )}
        style={{
          top: `${positionedEvent.top}%`,
          height: `${positionedEvent.height}%`,
          left: `${positionedEvent.left}%`,
          width: `${positionedEvent.width}%`,
          minHeight: "20px",
          zIndex: 15,
        }}
      >
        <div className="absolute inset-0 rounded-sm bg-white dark:bg-[#191919]" />
        <div className={cn("absolute inset-0 rounded-sm", styles.bg)} />
        <div
          className={cn(
            "absolute left-0 top-0 bottom-0 w-[4px] rounded-l-md dark:bg-white dark:mix-blend-overlay",
            styles.border,
          )}
        />
        <div
          className={cn(
            "relative flex flex-col h-full pl-1 overflow-hidden",
            isCompact && "flex-row items-center gap-1",
          )}
        >
          <span
            className={cn(
              "font-medium text-[0.625rem] leading-tight break-words",
              styles.text,
              "dark:text-white/80",
            )}
          >
            {event.title}
          </span>
          {!isCompact && (
            <span
              className={cn(
                "text-[0.625rem] whitespace-nowrap",
                styles.text,
                "dark:text-white dark:mix-blend-overlay",
              )}
            >
              {formatEventTimeRange(event)}
            </span>
          )}
        </div>
      </div>
    );
  }

  if (dragVariant === "placeholder") {
    return (
      <div
        className={cn(
          "absolute rounded-sm pointer-events-none border-2",
          styles.borderLine,
          className,
        )}
        style={{
          ...posStyle,
          left: "0%",
          width: "100%",
          zIndex: 25,
        }}
      />
    );
  }

  const isDraggingCopy = dragVariant === "dragging";

  if (isDraggingCopy) {
    const durationMinutes =
      (displayEnd.getTime() - displayStart.getTime()) / 60000;
    const heightPx = fixedHeight ?? (durationMinutes / 60) * hourHeight;

    const useFixed = cursorX != null && cursorY != null;

    const draggingStyle: React.CSSProperties = useFixed
      ? {
          position: "fixed",
          top: `${cursorY}px`,
          left: `${cursorX}px`,
          height: `${heightPx}px`,
          width: fixedWidth != null ? `${fixedWidth}px` : "200px",
          minHeight: "20px",
          zIndex: 30,
        }
      : {
          top: posStyle.top,
          height: `${heightPx}px`,
          left: `${positionedEvent.left}%`,
          width: `${positionedEvent.width}%`,
          minHeight: "20px",
          zIndex: 30,
        };

    return (
      <div
        tabIndex={-1}
        className={cn(
          "absolute rounded-sm px-2 py-1",
          "pointer-events-none cursor-grabbing",
          "overflow-hidden select-none opacity-80 shadow-lg",
          className,
        )}
        style={draggingStyle}
      >
        <div className="absolute inset-0 rounded-sm bg-white dark:bg-[#191919]" />
        <div className={cn("absolute inset-0 rounded-sm", styles.bg)} />
        <div
          className={cn(
            "absolute left-0 top-0 bottom-0 w-[4px] rounded-l-md dark:bg-white dark:mix-blend-overlay",
            styles.border,
          )}
        />
        <div
          className={cn(
            "relative flex flex-col h-full pl-1 overflow-hidden",
            heightPx < 40 && "flex-row items-center gap-1",
          )}
        >
          <span className="font-medium text-[0.625rem] leading-tight break-words text-white dark:text-white flex items-center gap-0.5">
            {event.title}
          </span>
          {heightPx >= 40 && (
            <span className="text-[0.625rem] whitespace-nowrap text-white dark:text-white">
              {formatEventTimeRange(displayEvent)}
            </span>
          )}
        </div>
      </div>
    );
  }

  function handleMouseMove(e: React.MouseEvent) {
    const target = e.currentTarget as HTMLElement;
    const rect = target.getBoundingClientRect();
    const offsetY = e.clientY - rect.top;
    const height = rect.height;

    if (showTopResize && showBottomResize && height < RESIZE_HOTZONE_PX * 2) {
      target.style.cursor = "row-resize";
      return;
    }

    if (showTopResize && offsetY <= RESIZE_HOTZONE_PX) {
      target.style.cursor = "row-resize";
      return;
    }

    if (showBottomResize && offsetY >= height - RESIZE_HOTZONE_PX) {
      target.style.cursor = "row-resize";
      return;
    }

    target.style.cursor = "default";
  }

  function handleMouseDown(e: React.MouseEvent) {
    e.stopPropagation();

    const target = e.currentTarget as HTMLElement;
    const rect = target.getBoundingClientRect();
    const offsetY = e.clientY - rect.top;
    const height = rect.height;

    if (showTopResize && showBottomResize && height < RESIZE_HOTZONE_PX * 2) {
      const edge = offsetY < height / 2 ? "top" : "bottom";
      onResizeMouseDown?.(e, event, edge);
      return;
    }

    if (showTopResize && offsetY <= RESIZE_HOTZONE_PX) {
      onResizeMouseDown?.(e, event, "top");
      return;
    }

    if (showBottomResize && offsetY >= height - RESIZE_HOTZONE_PX) {
      onResizeMouseDown?.(e, event, "bottom");
      return;
    }

    onDragMouseDown?.(e, event);
  }

  function handleClick(e: React.MouseEvent) {
    e.stopPropagation();
    if (!onClick) return;
    onClick(event);
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key !== "Enter" && e.key !== " ") return;
    e.preventDefault();
    onClick?.(event);
  }

  function handleContextMenu(e: React.MouseEvent) {
    e.preventDefault();
    e.stopPropagation();
    setContextMenu({ x: e.clientX, y: e.clientY });
    onContextMenuOpenChange?.(true);
  }

  const eventElement = (
    <div
      ref={eventRef}
      role="button"
      tabIndex={0}
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      onContextMenu={handleContextMenu}
      className={cn(
        "absolute px-2 py-1",
        hasTopRounding && "rounded-t-md",
        hasBottomRounding && "rounded-b-md",
        "cursor-default hover:z-10 focus:outline-none focus-visible:outline-none",
        "overflow-hidden select-none",
        isSelected && "z-20",
        className,
      )}
      style={{
        ...posStyle,
        zIndex: isSelected ? 20 : positionedEvent.column,
      }}
    >
      {/* Solid background layer to prevent transparency bleed-through */}
      <div
        className={cn(
          "absolute inset-0 bg-white dark:bg-[#191919]",
          hasTopRounding && "rounded-t-md",
          hasBottomRounding && "rounded-b-md",
        )}
      />

      {/* Colored background layer - uses border color when selected */}
      <div
        className={cn(
          "absolute inset-0",
          hasTopRounding && "rounded-t-md",
          hasBottomRounding && "rounded-b-md",
          isSelected ? styles.border : styles.bg,
          eventIsPast && !isSelected && "opacity-60",
        )}
      />

      {/* Left border - hidden when selected (merges with bg) */}
      {!isSelected && (
        <div
          className={cn(
            "absolute left-0 top-0 bottom-0 w-[4px] dark:bg-white dark:mix-blend-overlay",
            hasTopRounding && "rounded-tl-md",
            hasBottomRounding && "rounded-bl-md",
            styles.border,
            eventIsPast && "opacity-60",
          )}
        />
      )}
      <div
        className={cn(
          "relative flex flex-col h-full pl-1 overflow-hidden",
          isCompact && "flex-row items-center gap-1",
        )}
      >
        <span
          className={cn(
            "font-medium text-[0.625rem] leading-tight break-words flex items-center gap-0.5",
            isSelected
              ? "text-white dark:text-white"
              : cn(
                  styles.text,
                  "dark:text-white/80",
                  eventIsPast && "opacity-60",
                ),
          )}
        >
          {event.title}
        </span>
        {!isCompact && (
          <span
            className={cn(
              "text-[0.625rem] whitespace-nowrap",
              isSelected
                ? "text-white dark:text-white"
                : cn(
                    styles.text,
                    "dark:text-white dark:mix-blend-overlay",
                    eventIsPast && "opacity-60 dark:opacity-100",
                  ),
            )}
          >
            {formatEventTimeRange(displayEvent)}
          </span>
        )}
      </div>
    </div>
  );

  if (showPopover) {
    return (
      <>
        <Popover
          open
          onOpenChange={(open) => {
            if (!open) onClosePopover?.();
          }}
        >
          <PopoverTrigger asChild>{eventElement}</PopoverTrigger>
          {/*
           * In day view the event spans the full grid width, so Radix can't
           * fit the popover beside the trigger. Place a zero-width anchor at
           * the RIGHT edge of the calendar boundary and use side="left" so
           * the popover extends leftward \u2014 matching Notion Calendar.
           *
           * The anchor is portaled to document.body to escape scroll
           * containers that apply CSS transforms (which break position:fixed
           * by creating a new containing block).
           */}
          {isDayView &&
            createPortal(
              <PopoverAnchor
                className="pointer-events-none"
                style={{
                  position: "fixed",
                  left: boundaryRight,
                  top: anchorRect?.top ?? 0,
                  height: anchorRect?.height ?? 0,
                  width: 0,
                }}
              />,
              document.body,
            )}
          <EventDetailPopover
            event={event}
            onEventChange={onEventChange}
            onClose={() => onClosePopover?.()}
            onDockToSidebar={() => onDockToSidebar?.()}
            onPrevWeek={onPrevWeek}
            onNextWeek={onNextWeek}
            side={isDayView ? "left" : "right"}
            collisionPaddingTop={isDayView ? headerBottom : undefined}
          />
        </Popover>
        {contextMenu && (
          <EventContextMenu
            event={event}
            position={contextMenu}
            onClose={closeContextMenu}
            onEventChange={onEventChange}
          />
        )}
      </>
    );
  }

  return (
    <>
      {eventElement}
      {contextMenu && (
        <EventContextMenu
          event={event}
          position={contextMenu}
          onClose={closeContextMenu}
          onEventChange={onEventChange}
        />
      )}
    </>
  );
}

/** Drag visual variant for all-day events */
export type AllDayDragVariant = "ghost" | "placeholder" | "dragging";

export interface AllDayEventItemProps {
  event: CalendarEvent;
  isPast?: boolean;
  isSelected?: boolean;
  onClick?: (event: CalendarEvent) => void;
  className?: string;
  /** For multi-day events: position info */
  spanStart?: boolean;
  spanEnd?: boolean;
  /** Mousedown handler to initiate horizontal resize or drag */
  onResizeMouseDown?: (
    e: React.MouseEvent,
    event: CalendarEvent,
    edge: "left" | "right" | "move",
  ) => void;
  /** Callback when an event is changed (e.g. color change from context menu) */
  onEventChange?: (event: CalendarEvent) => void;
  /** Callback when context menu open state changes */
  onContextMenuOpenChange?: (open: boolean) => void;
  /** Whether the right sidebar is open (controls popover visibility) */
  isSidebarOpen?: boolean;
  /** Callback to dock popover to sidebar */
  onDockToSidebar?: () => void;
  /** Callback to close popover (deselect event) */
  onClosePopover?: () => void;
  /** Navigate to previous week */
  onPrevWeek?: () => void;
  /** Navigate to next week */
  onNextWeek?: () => void;
  /**
   * Percentage of the event's width that is hidden off-screen to the left.
   * Used in day view to offset the title into the visible area so multi-day
   * events always show their title \u2014 \u201csticky title\u201d effect.
   */
  titleOffsetPercent?: number;
  /** Visual variant during drag operations */
  dragVariant?: AllDayDragVariant;
}

/**
 * Formats start time for all-day events like "8:45 AM" or "4 PM"
 */
function formatAllDayStartTime(date: Date): string {
  const minutes = date.getMinutes();
  if (minutes === 0) {
    return format(date, "h a");
  }
  return format(date, "h:mm a");
}

const ALL_DAY_RESIZE_HOTZONE_PX = 6;

export function AllDayEventItem({
  event,
  isPast: isPastProp,
  isSelected,
  onClick,
  className,
  spanStart = true,
  spanEnd = true,
  onResizeMouseDown,
  onEventChange,
  onContextMenuOpenChange,
  isSidebarOpen,
  onDockToSidebar,
  onClosePopover,
  onPrevWeek,
  onNextWeek,
  titleOffsetPercent = 0,
  dragVariant,
}: AllDayEventItemProps) {
  const color = event.color ?? "blue";
  const styles = eventColorStyles[color];
  const { view, boundaryRight, headerBottom } = useCalendarPopoverBoundary();
  const isDayView = view === "day";
  const eventIsPast = isPastProp ?? isPast(event.end);

  const [contextMenu, setContextMenu] = React.useState<{
    x: number;
    y: number;
  } | null>(null);

  const closeContextMenu = React.useCallback(() => {
    setContextMenu(null);
    onContextMenuOpenChange?.(false);
  }, [onContextMenuOpenChange]);

  // Ghost: faded version at original position during move
  if (dragVariant === "ghost") {
    return (
      <div
        className={cn(
          "relative h-6 px-2 py-0.5 pointer-events-none opacity-30",
          "overflow-hidden select-none flex items-center gap-1",
          spanStart && "rounded-l-md",
          spanEnd && "rounded-r-md",
          className,
        )}
      >
        <div
          className={cn(
            "absolute inset-0 bg-white dark:bg-[#191919]",
            spanStart && "rounded-l-md",
            spanEnd && "rounded-r-md",
          )}
        />
        <div
          className={cn(
            "absolute inset-0",
            styles.bg,
            spanStart && "rounded-l-md",
            spanEnd && "rounded-r-md",
          )}
        />
        {spanStart && (
          <div
            className={cn(
              "absolute left-0 top-0 bottom-0 w-[4px] dark:bg-white dark:mix-blend-overlay",
              spanStart && "rounded-l-md",
              styles.border,
            )}
          />
        )}
        <span
          className={cn(
            "relative font-medium text-[0.625rem] leading-tight whitespace-nowrap",
            spanStart && "pl-1",
            styles.text,
            "dark:text-white/80",
          )}
        >
          {event.title}
        </span>
      </div>
    );
  }

  // Placeholder: border-only outline at target position
  if (dragVariant === "placeholder") {
    return (
      <div
        className={cn(
          "relative h-6 pointer-events-none border-2 rounded-sm",
          styles.borderLine,
          className,
        )}
      />
    );
  }

  // Dragging copy: floating replica following cursor
  if (dragVariant === "dragging") {
    return (
      <div
        className={cn(
          "h-6 px-2 py-0.5 pointer-events-none cursor-grabbing",
          "overflow-hidden select-none flex items-center gap-1",
          "rounded-sm opacity-80 shadow-lg",
          className,
        )}
      >
        <div className="absolute inset-0 rounded-sm bg-white dark:bg-[#191919]" />
        <div className={cn("absolute inset-0 rounded-sm", styles.bg)} />
        <div
          className={cn(
            "absolute left-0 top-0 bottom-0 w-[4px] rounded-l-md dark:bg-white dark:mix-blend-overlay",
            styles.border,
          )}
        />
        <span
          className={cn(
            "relative font-medium text-[0.625rem] leading-tight whitespace-nowrap pl-1",
            styles.text,
            "dark:text-white/80",
          )}
        >
          {event.title}
        </span>
      </div>
    );
  }

  // Check if event has a specific start time (not midnight)
  const hasStartTime =
    event.start.getHours() !== 0 || event.start.getMinutes() !== 0;

  function handleClick(e: React.MouseEvent) {
    e.stopPropagation();
    if (!onClick) {
      return;
    }
    onClick(event);
  }

  function handleKeyDown(e: React.KeyboardEvent) {
    if (e.key !== "Enter" && e.key !== " ") {
      return;
    }
    e.preventDefault();
    onClick?.(event);
  }

  function handleAllDayMouseMove(e: React.MouseEvent) {
    const target = e.currentTarget as HTMLElement;
    const rect = target.getBoundingClientRect();
    const offsetX = e.clientX - rect.left;
    const width = rect.width;

    if (spanStart && offsetX <= ALL_DAY_RESIZE_HOTZONE_PX) {
      target.style.cursor = "col-resize";
      return;
    }

    if (spanEnd && offsetX >= width - ALL_DAY_RESIZE_HOTZONE_PX) {
      target.style.cursor = "col-resize";
      return;
    }

    target.style.cursor = "default";
  }

  function handleAllDayMouseDown(e: React.MouseEvent) {
    if (!onResizeMouseDown) return;

    const target = e.currentTarget as HTMLElement;
    const rect = target.getBoundingClientRect();
    const offsetX = e.clientX - rect.left;
    const width = rect.width;

    if (spanStart && offsetX <= ALL_DAY_RESIZE_HOTZONE_PX) {
      e.stopPropagation();
      onResizeMouseDown(e, event, "left");
      return;
    }

    if (spanEnd && offsetX >= width - ALL_DAY_RESIZE_HOTZONE_PX) {
      e.stopPropagation();
      onResizeMouseDown(e, event, "right");
      return;
    }

    // Middle area: initiate drag (move)
    e.stopPropagation();
    onResizeMouseDown(e, event, "move");
  }

  function handleContextMenu(e: React.MouseEvent) {
    e.preventDefault();
    e.stopPropagation();
    setContextMenu({ x: e.clientX, y: e.clientY });
    onContextMenuOpenChange?.(true);
  }

  const showPopover = isSelected && isSidebarOpen === false;

  const eventElement = (
    <div
      role="button"
      tabIndex={0}
      onClick={handleClick}
      onKeyDown={handleKeyDown}
      onContextMenu={handleContextMenu}
      onMouseMove={handleAllDayMouseMove}
      onMouseDown={handleAllDayMouseDown}
      className={cn(
        "relative h-6 px-2 py-0.5 cursor-default",
        "hover:z-10 focus:outline-none focus-visible:outline-none",
        "overflow-hidden select-none flex items-center gap-1",
        spanStart && "rounded-l-md",
        spanEnd && "rounded-r-md",
        isSelected && "z-20",
        className,
      )}
      style={
        titleOffsetPercent > 0
          ? { paddingLeft: `${titleOffsetPercent}%` }
          : undefined
      }
    >
      {/* Solid background layer to prevent transparency bleed-through */}
      <div
        className={cn(
          "absolute inset-0 bg-white dark:bg-[#191919]",
          spanStart && "rounded-l-md",
          spanEnd && "rounded-r-md",
        )}
      />

      {/* Colored background layer - uses border color when selected */}
      <div
        className={cn(
          "absolute inset-0",
          isSelected ? styles.border : styles.bg,
          spanStart && "rounded-l-md",
          spanEnd && "rounded-r-md",
          eventIsPast && !isSelected && "opacity-60",
        )}
      />

      {/* Left border - hidden when selected (merges with bg) */}
      {spanStart && !isSelected && (
        <div
          className={cn(
            "absolute left-0 top-0 bottom-0 w-[4px] dark:bg-white dark:mix-blend-overlay",
            spanStart && "rounded-l-md",
            styles.border,
            eventIsPast && "opacity-60",
          )}
        />
      )}
      <span
        className={cn(
          "relative font-medium text-[0.625rem] leading-tight whitespace-nowrap",
          spanStart && "pl-1",
          isSelected
            ? "text-white dark:text-white"
            : cn(
                styles.text,
                "dark:text-white/80",
                eventIsPast && "opacity-60",
              ),
        )}
      >
        {event.title}
      </span>
      {hasStartTime && (
        <span
          className={cn(
            "relative text-[0.625rem] leading-tight whitespace-nowrap shrink-0",
            isSelected
              ? "text-white dark:text-white"
              : cn(
                  styles.text,
                  "dark:text-white dark:mix-blend-overlay",
                  eventIsPast && "opacity-60",
                ),
          )}
        >
          {formatAllDayStartTime(event.start)}
        </span>
      )}
    </div>
  );

  if (showPopover) {
    return (
      <>
        <Popover
          open
          onOpenChange={(open) => {
            if (!open) onClosePopover?.();
          }}
        >
          <PopoverTrigger asChild>{eventElement}</PopoverTrigger>
          {/*
           * In day view, all-day events span the full width. Portal the
           * anchor to document.body (escaping transformed scroll containers)
           * and position it at the calendar boundary's right edge so the
           * popover always appears at the visible right edge \u2014 even when the
           * event wrapper extends into off-screen buffer days.
           */}
          {isDayView &&
            createPortal(
              <PopoverAnchor
                className="pointer-events-none"
                style={{
                  position: "fixed",
                  left: boundaryRight,
                  top: 0,
                  bottom: 0,
                  width: 0,
                }}
              />,
              document.body,
            )}
          <EventDetailPopover
            event={event}
            onEventChange={onEventChange}
            onClose={() => onClosePopover?.()}
            onDockToSidebar={() => onDockToSidebar?.()}
            onPrevWeek={onPrevWeek}
            onNextWeek={onNextWeek}
            side={isDayView ? "left" : "right"}
            align="start"
            collisionPaddingTop={isDayView ? headerBottom : undefined}
          />
        </Popover>
        {contextMenu && (
          <EventContextMenu
            event={event}
            position={contextMenu}
            onClose={closeContextMenu}
            onEventChange={onEventChange}
          />
        )}
      </>
    );
  }

  return (
    <>
      {eventElement}
      {contextMenu && (
        <EventContextMenu
          event={event}
          position={contextMenu}
          onClose={closeContextMenu}
          onEventChange={onEventChange}
        />
      )}
    </>
  );
}

"use client";

import * as React from "react";

import type { ViewType } from "./week-view-types";

/**
 * Context to provide the collision boundary element, header inset,
 * and current view type for event detail popovers.
 * - boundary: the outer calendar container (so popovers can position freely)
 * - headerHeight: the height of the weekday header + all-day row,
 *   used as top collision padding so popovers never overlap the header.
 * - view: current calendar view ("day" | "week") — in day view, the collision
 *   boundary is skipped so Radix uses the viewport for positioning.
 * - boundaryRight: the right-edge x-coordinate (in viewport px) of the
 *   calendar boundary. Used in day view to place a fixed-position popover
 *   anchor at the calendar's right edge so popovers match Notion Calendar.
 */

interface CalendarPopoverBoundaryValue {
  boundary: HTMLElement | null;
  headerHeight: number;
  view: ViewType;
  /** Right edge of the calendar boundary in viewport pixels. */
  boundaryRight: number;
  /**
   * Bottom edge of the header (weekday + all-day row) in viewport pixels.
   * Used as collision padding top in day view so the popover never overlaps
   * the header area when the collision boundary is the viewport.
   */
  headerBottom: number;
}

const CalendarPopoverBoundaryContext =
  React.createContext<CalendarPopoverBoundaryValue>({
    boundary: null,
    headerHeight: 0,
    view: "week",
    boundaryRight: 0,
    headerBottom: 0,
  });

export function CalendarPopoverBoundaryProvider({
  boundaryRef,
  headerRef,
  view = "week",
  children,
}: {
  boundaryRef: React.RefObject<HTMLElement | null>;
  headerRef: React.RefObject<HTMLElement | null>;
  view?: ViewType;
  children: React.ReactNode;
}) {
  const [boundary, setBoundary] = React.useState<HTMLElement | null>(null);
  const [headerHeight, setHeaderHeight] = React.useState(0);
  const [boundaryRight, setBoundaryRight] = React.useState(0);
  const [headerBottom, setHeaderBottom] = React.useState(0);

  React.useEffect(() => {
    setBoundary(boundaryRef.current);
  }, [boundaryRef]);

  // Observe header height changes (all-day row can expand/collapse).
  // Also track the viewport-relative bottom edge of the header for day-view
  // collision padding — the popover must not overlap the header area.
  React.useEffect(() => {
    const el = headerRef.current;
    if (!el) return;

    const update = () => {
      setHeaderHeight(el.offsetHeight);
      setHeaderBottom(el.getBoundingClientRect().bottom);
    };
    update();

    const ro = new ResizeObserver(update);
    ro.observe(el);
    return () => ro.disconnect();
  }, [headerRef]);

  // Track the right edge of the calendar boundary for day-view anchoring.
  // A ResizeObserver catches layout changes; we don't need scroll since the
  // boundary element itself doesn't scroll within the viewport.
  React.useEffect(() => {
    const el = boundaryRef.current;
    if (!el) return;

    const update = () => {
      setBoundaryRight(el.getBoundingClientRect().right);
    };
    update();

    const ro = new ResizeObserver(update);
    ro.observe(el);
    return () => ro.disconnect();
  }, [boundaryRef]);

  const value = React.useMemo(
    () => ({ boundary, headerHeight, view, boundaryRight, headerBottom }),
    [boundary, headerHeight, view, boundaryRight, headerBottom],
  );

  return (
    <CalendarPopoverBoundaryContext.Provider value={value}>
      {children}
    </CalendarPopoverBoundaryContext.Provider>
  );
}

export function useCalendarPopoverBoundary() {
  return React.useContext(CalendarPopoverBoundaryContext);
}

"use client";

import * as React from "react";
import { ChevronRight, Eye, EyeOff, Rss } from "lucide-react";

import { cn } from "@/lib/utils";
import type {
  CalendarAccount,
  CalendarColor,
} from "@/components/layouts/calendar/sidebar-right";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import {
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarSeparator,
} from "@/components/ui/sidebar";

const colorStyles: Record<CalendarColor, string> = {
  red: "bg-event-red",
  orange: "bg-event-orange",
  yellow: "bg-event-yellow",
  green: "bg-event-green",
  blue: "bg-event-blue",
  purple: "bg-event-purple",
  gray: "bg-event-gray",
};

interface CalendarsProps {
  accounts: CalendarAccount[];
}

export function Calendars({ accounts }: CalendarsProps) {
  const [visibleCalendars, setVisibleCalendars] = React.useState<Set<string>>(
    () => {
      const visible = new Set<string>();
      for (const account of accounts) {
        for (const calendar of account.calendars) {
          if (calendar.visible) {
            visible.add(`${account.email}-${calendar.name}`);
          }
        }
      }
      return visible;
    },
  );

  const toggleVisibility = (accountEmail: string, calendarName: string) => {
    const key = `${accountEmail}-${calendarName}`;
    setVisibleCalendars((prev) => {
      const next = new Set(prev);
      if (next.has(key)) {
        next.delete(key);
      } else {
        next.add(key);
      }
      return next;
    });
  };

  return (
    <>
      {accounts.map((account, index) => (
        <React.Fragment key={account.email}>
          <SidebarGroup className="py-0">
            <Collapsible defaultOpen className="group/collapsible">
              <SidebarGroupLabel
                asChild
                className="group/label text-sidebar-foreground hover:bg-sidebar-accent hover:text-sidebar-accent-foreground w-full text-xs"
              >
                <CollapsibleTrigger>
                  <span className="truncate">{account.email}</span>
                  <ChevronRight className="ml-auto shrink-0 opacity-0 transition-transform group-hover/label:opacity-100 group-data-[state=open]/collapsible:rotate-90" />
                </CollapsibleTrigger>
              </SidebarGroupLabel>
              <CollapsibleContent>
                <SidebarGroupContent>
                  <SidebarMenu className="gap-0">
                    {account.calendars.map((calendar) => {
                      const isVisible = visibleCalendars.has(
                        `${account.email}-${calendar.name}`,
                      );
                      return (
                        <SidebarMenuItem
                          key={calendar.name}
                          className="group/calendar-item"
                        >
                          <SidebarMenuButton className="pr-1">
                            <div
                              className={cn(
                                "size-3 shrink-0 flex items-center justify-center rounded-xs",
                                colorStyles[calendar.color],
                                !isVisible && "opacity-40",
                              )}
                            >
                              {calendar.isSubscribed && (
                                <Rss className="size-2 text-white" />
                              )}
                            </div>
                            <span
                              className={cn(
                                "flex-1 truncate text-xs text-sidebar-foreground",
                                !isVisible && "opacity-50",
                              )}
                            >
                              {calendar.name}
                            </span>
                            <span
                              role="button"
                              tabIndex={0}
                              className="inline-flex size-6 shrink-0 items-center justify-center rounded-sm opacity-0 hover:bg-sidebar-accent group-hover/calendar-item:opacity-100"
                              onClick={(e) => {
                                e.stopPropagation();
                                toggleVisibility(account.email, calendar.name);
                              }}
                              onKeyDown={(e) => {
                                if (e.key === "Enter" || e.key === " ") {
                                  e.preventDefault();
                                  e.stopPropagation();
                                  toggleVisibility(
                                    account.email,
                                    calendar.name,
                                  );
                                }
                              }}
                            >
                              {isVisible ? (
                                <Eye className="size-3.5 text-sidebar-muted-foreground" />
                              ) : (
                                <EyeOff className="size-3.5 text-sidebar-muted-foreground" />
                              )}
                            </span>
                          </SidebarMenuButton>
                        </SidebarMenuItem>
                      );
                    })}
                  </SidebarMenu>
                </SidebarGroupContent>
              </CollapsibleContent>
            </Collapsible>
          </SidebarGroup>
          {index < accounts.length - 1 && <SidebarSeparator className="mx-0" />}
        </React.Fragment>
      ))}
    </>
  );
}

"use client";

import * as React from "react";
import { isSameDay } from "date-fns";

import { Calendar } from "@/components/ui/calendar";
import { SidebarGroup, SidebarGroupContent } from "@/components/ui/sidebar";

interface DatePickerProps {
  onDateSelect?: (date: Date) => void;
  currentDate?: Date;
  visibleDays?: Date[];
}

export function DatePicker({
  onDateSelect,
  currentDate,
  visibleDays,
}: DatePickerProps) {
  const [today] = React.useState(() => new Date());
  const [displayedMonth, setDisplayedMonth] = React.useState<Date>(
    currentDate ?? today,
  );

  // Track previous first visible day to determine scroll direction
  const prevFirstDayRef = React.useRef<Date | null>(null);

  // Auto-navigate datepicker month so highlighted days stay visible
  // Scrolling forward → keep last visible day's month shown
  // Scrolling backward → keep first visible day's month shown
  React.useEffect(() => {
    if (!visibleDays || visibleDays.length === 0) return;

    const firstDay = visibleDays[0];
    const lastDay = visibleDays[visibleDays.length - 1];
    const prevFirstDay = prevFirstDayRef.current;
    prevFirstDayRef.current = firstDay;

    const setMonthIfChanged = (anchor: Date) => {
      setDisplayedMonth((prev) => {
        if (
          prev.getMonth() === anchor.getMonth() &&
          prev.getFullYear() === anchor.getFullYear()
        ) {
          return prev;
        }
        return anchor;
      });
    };

    // Scrolling forward → ensure last visible day's month is displayed
    if (prevFirstDay && firstDay.getTime() > prevFirstDay.getTime()) {
      setMonthIfChanged(lastDay);
      return;
    }

    // Scrolling backward or initial render → ensure first visible day's month is displayed
    setMonthIfChanged(firstDay);
  }, [visibleDays]);

  const isSameMonth =
    displayedMonth.getMonth() === today.getMonth() &&
    displayedMonth.getFullYear() === today.getFullYear();

  const monthYearLabel = displayedMonth.toLocaleDateString("default", {
    month: "long",
    year: "numeric",
  });

  const goBackToToday = () => {
    setDisplayedMonth(today);
    onDateSelect?.(today);
  };

  // Build modifiers for visible days highlighting
  const modifiers = React.useMemo(() => {
    if (!visibleDays || visibleDays.length === 0) return undefined;

    return {
      inView: (date: Date) => visibleDays.some((d) => isSameDay(d, date)),
    };
  }, [visibleDays]);

  const modifiersClassNames = React.useMemo(() => {
    if (!modifiers) return undefined;
    return {
      inView: "in-view-day",
    };
  }, [modifiers]);

  return (
    // Pin the mini calendar to the top of the sidebar scroll container so
    // it stays visible while the sections below (Scheduling, accounts,
    // teams) scroll underneath.
    <SidebarGroup className="sticky top-0 z-10 bg-sidebar px-0">
      <SidebarGroupContent>
        <Calendar
          mode="single"
          month={displayedMonth}
          onMonthChange={setDisplayedMonth}
          selected={today}
          onSelect={(date) => {
            if (date) {
              onDateSelect?.(date);
            }
          }}
          fixedWeeks
          modifiers={modifiers}
          modifiersClassNames={modifiersClassNames}
          // Dropping showWeekNumber: react-day-picker v8 adds the week column
          // only to tbody rows, not to the header row, so headers and data
          // were off-by-one — Saturday was shoved off the right edge. A
          // clean 7-column grid (7 × 32px + padding ≈ 240px) fits the
          // ~256px sidebar without clipping.
          className="bg-transparent [&_[role=gridcell].bg-accent]:bg-sidebar-primary [&_[role=gridcell].bg-accent]:text-sidebar-primary-foreground"
        />
      </SidebarGroupContent>
    </SidebarGroup>
  );
}

"use client";

import * as React from "react";
