"use client";

import { useState, useEffect, useRef, useId } from "react";
import { useTheme } from "next-themes";
import { motion } from "motion/react";

/* ── Audio ── */

let _ctx: AudioContext | null = null;
let _buf: AudioBuffer | null = null;

function audioCtx() {
  if (!_ctx) {
    _ctx = new (window.AudioContext ||
      (window as unknown as { webkitAudioContext: typeof AudioContext })
        .webkitAudioContext)();
  }
  if (_ctx.state === "suspended") _ctx.resume();
  return _ctx;
}

function ensureBuf(ac: AudioContext): AudioBuffer {
  if (_buf && _buf.sampleRate === ac.sampleRate) return _buf;
  const rate = ac.sampleRate;
  const len = Math.floor(rate * 0.006);
  const buf = ac.createBuffer(1, len, rate);
  const ch = buf.getChannelData(0);
  for (let i = 0; i < len; i++) {
    const t = i / len;
    const sine = Math.sin(2 * Math.PI * 3400 * t);
    const noise = Math.random() * 2 - 1;
    ch[i] = (sine * 0.6 + noise * 0.4) * (1 - t) ** 3;
  }
  _buf = buf;
  return buf;
}

function tick(last: React.MutableRefObject<number>) {
  const now = performance.now();
  if (now - last.current < 80) return;
  last.current = now;
  try {
    const ac = audioCtx();
    const buf = ensureBuf(ac);
    const src = ac.createBufferSource();
    const gain = ac.createGain();
    src.buffer = buf;
    gain.gain.value = 0.08;
    src.connect(gain);
    gain.connect(ac.destination);
    src.start();
  } catch {
    /* silent */
  }
}

/* ── Component ── */

export function ModeToggle() {
  const { resolvedTheme, setTheme } = useTheme();
  const rawId = useId();
  const maskId = `mt${rawId.replace(/:/g, "")}`;
  const lastSnd = useRef(0);
  const isFirst = useRef(true);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    requestAnimationFrame(() => {
      isFirst.current = false;
    });
  }, []);

  const isDark = resolvedTheme === "dark";

  const toggle = () => {
    setTheme(isDark ? "light" : "dark");
    tick(lastSnd);
  };

  /* Placeholder during SSR to avoid layout shift */
  if (!mounted) {
    return <div style={{ width: 32, height: 32 }} />;
  }

  const spring = isFirst.current
    ? { duration: 0 }
    : { type: "spring" as const, stiffness: 380, damping: 30 };

  return (
    <motion.button
      onClick={toggle}
      whileHover={{ scale: 1.1 }}
      whileTap={{ scale: 0.86 }}
      transition={{ type: "spring", stiffness: 400, damping: 25 }}
      style={{
        background: "none",
        border: "none",
        cursor: "pointer",
        padding: 6,
        width: 32,
        height: 32,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        color: "currentColor",
        borderRadius: 8,
        outline: "none",
        WebkitTapHighlightColor: "transparent",
      }}
      aria-label="Toggle theme"
    >
      <motion.svg
        width="18"
        height="18"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        initial={false}
        animate={{ rotate: isDark ? 270 : 0 }}
        transition={spring}
        style={{ overflow: "visible" }}
      >
        <mask id={maskId}>
          <rect x="0" y="0" width="100%" height="100%" fill="white" />
          <motion.circle
            initial={false}
            animate={{ cx: isDark ? 17 : 33, cy: isDark ? 8 : 0 }}
            transition={spring}
            r="9"
            fill="black"
          />
        </mask>

        <motion.circle
          cx="12"
          cy="12"
          fill="currentColor"
          stroke="none"
          mask={`url(#${maskId})`}
          initial={false}
          animate={{ r: isDark ? 9 : 5 }}
          transition={spring}
        />

        <motion.g
          initial={false}
          animate={{
            opacity: isDark ? 0 : 1,
            scale: isDark ? 0 : 1,
            rotate: isDark ? -30 : 0,
          }}
          transition={spring}
          style={{ transformOrigin: "12px 12px" }}
        >
          <line x1="12" y1="1" x2="12" y2="3" />
          <line x1="12" y1="21" x2="12" y2="23" />
          <line x1="1" y1="12" x2="3" y2="12" />
          <line x1="21" y1="12" x2="23" y2="12" />
          <line x1="5.64" y1="5.64" x2="4.22" y2="4.22" />
          <line x1="18.36" y1="5.64" x2="19.78" y2="4.22" />
          <line x1="5.64" y1="18.36" x2="4.22" y2="19.78" />
          <line x1="18.36" y1="18.36" x2="19.78" y2="19.78" />
        </motion.g>
      </motion.svg>
    </motion.button>
  );
}

ModeToggle.displayName = "ModeToggle";

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type {
  AllDayResizeState,
  CalendarEvent,
} from "@/components/layouts/calendar/week-view-types";

interface UseAllDayResizeOptions {
  days: Date[];
  dayColumnWidth: number;
  allDayContainerRef: React.RefObject<HTMLDivElement | null>;
  events: CalendarEvent[];
  onEventChange?: (event: CalendarEvent) => void;
  onEventClick?: (event: CalendarEvent) => void;
}

interface UseAllDayResizeReturn {
  allDayResizeState: AllDayResizeState | null;
  handleAllDayResizeMouseDown: (
    e: React.MouseEvent,
    event: CalendarEvent,
    edge: "left" | "right" | "move",
    startColumn: number,
    endColumn: number,
  ) => void;
}

const DRAG_THRESHOLD_PX = 4;

function clamp(value: number, min: number, max: number): number {
  if (value < min) return min;
  if (value > max) return max;
  return value;
}

interface ResizeInfo {
  eventId: string;
  event: CalendarEvent;
  edge: "left" | "right" | "move";
  startClientX: number;
  isResizing: boolean;
  originalStartColumn: number;
  originalEndColumn: number;
  /** Column index at the initial mousedown position (used for move delta) */
  startColumnIndex: number;
  /** Offset from cursor to event left edge at mousedown (px) */
  cursorOffsetX: number;
  /** Offset from cursor to event top edge at mousedown (px) */
  cursorOffsetY: number;
}

export function useAllDayResize({
  days,
  dayColumnWidth,
  allDayContainerRef,
  events,
  onEventChange,
  onEventClick,
}: UseAllDayResizeOptions): UseAllDayResizeReturn {
  const [allDayResizeState, setAllDayResizeState] =
    useState<AllDayResizeState | null>(null);

  const resizeRef = useRef<ResizeInfo | null>(null);
  const onEventChangeRef = useRef(onEventChange);
  const onEventClickRef = useRef(onEventClick);
  const eventsRef = useRef(events);
  const daysRef = useRef(days);
  const dayColumnWidthRef = useRef(dayColumnWidth);

  useEffect(() => {
    onEventChangeRef.current = onEventChange;
  }, [onEventChange]);
  useEffect(() => {
    onEventClickRef.current = onEventClick;
  }, [onEventClick]);
  useEffect(() => {
    eventsRef.current = events;
  }, [events]);
  useEffect(() => {
    daysRef.current = days;
  }, [days]);
  useEffect(() => {
    dayColumnWidthRef.current = dayColumnWidth;
  }, [dayColumnWidth]);

  const handleMouseMoveRef = useRef<((e: MouseEvent) => void) | null>(null);
  const handleMouseUpRef = useRef<(() => void) | null>(null);

  const cleanup = useCallback(() => {
    if (handleMouseMoveRef.current) {
      window.removeEventListener("mousemove", handleMouseMoveRef.current);
    }
    if (handleMouseUpRef.current) {
      window.removeEventListener("mouseup", handleMouseUpRef.current);
    }
    document.body.style.cursor = "";
  }, []);

  useEffect(() => {
    handleMouseMoveRef.current = (e: MouseEvent) => {
      const resize = resizeRef.current;
      if (!resize) return;

      const deltaX = Math.abs(e.clientX - resize.startClientX);
      if (!resize.isResizing && deltaX < DRAG_THRESHOLD_PX) return;

      if (!resize.isResizing) {
        resize.isResizing = true;
        document.body.style.cursor =
          resize.edge === "move" ? "grabbing" : "col-resize";
      }

      const container = allDayContainerRef.current;
      if (!container) return;

      const rect = container.getBoundingClientRect();
      const colWidth = dayColumnWidthRef.current;
      const currentDays = daysRef.current;
      const columnIndex = clamp(
        Math.floor((e.clientX - rect.left) / colWidth),
        0,
        currentDays.length - 1,
      );

      let newStartColumn = resize.originalStartColumn;
      let newEndColumn = resize.originalEndColumn;

      if (resize.edge === "move") {
        const span = resize.originalEndColumn - resize.originalStartColumn;
        const delta = columnIndex - resize.startColumnIndex;
        newStartColumn = clamp(
          resize.originalStartColumn + delta,
          0,
          currentDays.length - 1 - span,
        );
        newEndColumn = newStartColumn + span;
      } else if (resize.edge === "right") {
        newEndColumn = Math.max(columnIndex, resize.originalStartColumn);
      } else {
        newStartColumn = Math.min(columnIndex, resize.originalEndColumn);
      }

      setAllDayResizeState({
        eventId: resize.eventId,
        event: resize.event,
        originalStartColumn: resize.originalStartColumn,
        originalEndColumn: resize.originalEndColumn,
        currentStartColumn: newStartColumn,
        currentEndColumn: newEndColumn,
        edge: resize.edge,
        isResizing: true,
        ...(resize.edge === "move"
          ? {
              clientX: e.clientX,
              clientY: e.clientY,
              cursorOffsetX: resize.cursorOffsetX,
              cursorOffsetY: resize.cursorOffsetY,
            }
          : {}),
      });
    };

    handleMouseUpRef.current = () => {
      const resize = resizeRef.current;
      if (!resize) return;

      cleanup();

      if (resize.isResizing) {
        setAllDayResizeState((prev) => {
          if (!prev) return null;

          const event = eventsRef.current.find((e) => e.id === resize.eventId);
          if (!event) return null;

          const currentDays = daysRef.current;
          const newStartDate = currentDays[prev.currentStartColumn];
          const newEndDate = currentDays[prev.currentEndColumn];

          if (!newStartDate || !newEndDate) return null;

          // Preserve time-of-day from original event
          const newStart = new Date(newStartDate);
          newStart.setHours(
            event.start.getHours(),
            event.start.getMinutes(),
            event.start.getSeconds(),
            event.start.getMilliseconds(),
          );

          const newEnd = new Date(newEndDate);
          newEnd.setHours(
            event.end.getHours(),
            event.end.getMinutes(),
            event.end.getSeconds(),
            event.end.getMilliseconds(),
          );

          // Move preserves the original isAllDay flag (duration unchanged).
          // Resize determines isAllDay by whether the span exceeds 24h.
          const isMove = resize.edge === "move";
          const MS_IN_24H = 24 * 60 * 60 * 1000;
          const isLongerThan24h =
            newEnd.getTime() - newStart.getTime() > MS_IN_24H;
          const isAllDay = isMove ? event.isAllDay === true : isLongerThan24h;

          onEventChangeRef.current?.({
            ...event,
            start: newStart,
            end: newEnd,
            isAllDay,
          });

          return null;
        });
      } else {
        setAllDayResizeState(null);
      }

      resizeRef.current = null;
    };
  }, [allDayContainerRef, cleanup]);

  const handleAllDayResizeMouseDown = useCallback(
    (
      e: React.MouseEvent,
      event: CalendarEvent,
      edge: "left" | "right" | "move",
      startColumn: number,
      endColumn: number,
    ) => {
      if (e.button !== 0) return;

      e.stopPropagation();

      onEventClickRef.current?.(event);

      // Compute the column under the cursor at mousedown for move delta
      const container = allDayContainerRef.current;
      let startColumnIndex = startColumn;
      let cursorOffsetX = 0;
      const cursorOffsetY = 0;
      if (container) {
        const rect = container.getBoundingClientRect();
        const colWidth = dayColumnWidthRef.current;
        startColumnIndex = clamp(
          Math.floor((e.clientX - rect.left) / colWidth),
          0,
          daysRef.current.length - 1,
        );
        // Compute offset from cursor to the event element's top-left
        const eventLeft = rect.left + startColumn * colWidth;
        cursorOffsetX = e.clientX - eventLeft;
      }

      resizeRef.current = {
        eventId: event.id,
        event,
        edge,
        startClientX: e.clientX,
        isResizing: false,
        originalStartColumn: startColumn,
        originalEndColumn: endColumn,
        startColumnIndex,
        cursorOffsetX,
        cursorOffsetY,
      };

      setAllDayResizeState({
        eventId: event.id,
        event,
        originalStartColumn: startColumn,
        originalEndColumn: endColumn,
        currentStartColumn: startColumn,
        currentEndColumn: endColumn,
        edge,
        isResizing: false,
      });

      if (handleMouseMoveRef.current) {
        window.addEventListener("mousemove", handleMouseMoveRef.current);
      }
      if (handleMouseUpRef.current) {
        window.addEventListener("mouseup", handleMouseUpRef.current);
      }
    },
    [allDayContainerRef],
  );

  useEffect(() => {
    return cleanup;
  }, [cleanup]);

  return { allDayResizeState, handleAllDayResizeMouseDown };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type {
  CalendarEvent,
  EventDragState,
} from "@/components/layouts/calendar/week-view-types";

interface UseEventDragOptions {
  hourHeight: number;
  scrollContainerRef: React.RefObject<HTMLDivElement | null>;
  events: CalendarEvent[];
  days: Date[];
  dayColumnWidth: number;
  timeAxisWidth: number;
  onEventChange?: (event: CalendarEvent) => void;
  onEventClick?: (event: CalendarEvent) => void;
  onDragNavigate?: (daysDelta: number) => void;
}

interface UseEventDragReturn {
  dragState: EventDragState | null;
  handleEventMouseDown: (e: React.MouseEvent, event: CalendarEvent) => void;
}

const DRAG_THRESHOLD_PX = 4;
const SNAP_MINUTES = 15;
const EDGE_ZONE_PX = 40;
const EDGE_NAV_DELAY_MS = 500;
const EDGE_NAV_REPEAT_MS = 800;
const AUTO_SCROLL_ZONE_PX = 60;
const AUTO_SCROLL_MAX_SPEED = 12;

function snapToGrid(minutes: number): number {
  return Math.round(minutes / SNAP_MINUTES) * SNAP_MINUTES;
}

function addMinutesToDate(date: Date, minutes: number): Date {
  const result = new Date(date);
  result.setHours(0, 0, 0, 0);
  result.setMinutes(minutes);
  return result;
}

function clamp(value: number, min: number, max: number): number {
  if (value < min) return min;
  if (value > max) return max;
  return value;
}

interface DragInfo {
  eventId: string;
  event: CalendarEvent;
  startClientY: number;
  startClientX: number;
  offsetWithinEvent: number;
  offsetWithinEventX: number;
  isDragging: boolean;
  durationMinutes: number;
}

export function useEventDrag({
  hourHeight,
  scrollContainerRef,
  events,
  days,
  dayColumnWidth,
  timeAxisWidth,
  onEventChange,
  onEventClick,
  onDragNavigate,
}: UseEventDragOptions): UseEventDragReturn {
  const [dragState, setDragState] = useState<EventDragState | null>(null);

  const dragRef = useRef<DragInfo | null>(null);
  const onEventChangeRef = useRef(onEventChange);
  const onEventClickRef = useRef(onEventClick);
  const onDragNavigateRef = useRef(onDragNavigate);
  const eventsRef = useRef(events);
  const hourHeightRef = useRef(hourHeight);
  const daysRef = useRef(days);
  const dayColumnWidthRef = useRef(dayColumnWidth);
  const timeAxisWidthRef = useRef(timeAxisWidth);

  useEffect(() => {
    onEventChangeRef.current = onEventChange;
  }, [onEventChange]);
  useEffect(() => {
    onEventClickRef.current = onEventClick;
  }, [onEventClick]);
  useEffect(() => {
    onDragNavigateRef.current = onDragNavigate;
  }, [onDragNavigate]);
  useEffect(() => {
    eventsRef.current = events;
  }, [events]);
  useEffect(() => {
    hourHeightRef.current = hourHeight;
  }, [hourHeight]);
  useEffect(() => {
    daysRef.current = days;
  }, [days]);
  useEffect(() => {
    dayColumnWidthRef.current = dayColumnWidth;
  }, [dayColumnWidth]);
  useEffect(() => {
    timeAxisWidthRef.current = timeAxisWidth;
  }, [timeAxisWidth]);

  // Edge navigation timer refs
  const edgeNavTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const edgeNavDirectionRef = useRef<number | null>(null);

  // Auto-scroll RAF ref
  const autoScrollRAFRef = useRef<number | null>(null);
  const autoScrollSpeedRef = useRef(0);

  // Store handlers in refs to break the circular dependency
  const handleMouseMoveRef = useRef<((e: MouseEvent) => void) | null>(null);
  const handleMouseUpRef = useRef<(() => void) | null>(null);

  const cancelEdgeNav = useCallback(() => {
    if (edgeNavTimerRef.current !== null) {
      clearTimeout(edgeNavTimerRef.current);
      edgeNavTimerRef.current = null;
    }
    edgeNavDirectionRef.current = null;
  }, []);

  const cancelAutoScroll = useCallback(() => {
    if (autoScrollRAFRef.current !== null) {
      cancelAnimationFrame(autoScrollRAFRef.current);
      autoScrollRAFRef.current = null;
    }
    autoScrollSpeedRef.current = 0;
  }, []);

  const cleanup = useCallback(() => {
    if (handleMouseMoveRef.current) {
      window.removeEventListener("mousemove", handleMouseMoveRef.current);
    }
    if (handleMouseUpRef.current) {
      window.removeEventListener("mouseup", handleMouseUpRef.current);
    }
    cancelEdgeNav();
    cancelAutoScroll();
  }, [cancelEdgeNav, cancelAutoScroll]);

  // Auto-scroll loop
  const startAutoScrollLoop = useCallback(() => {
    if (autoScrollRAFRef.current !== null) return;

    const tick = () => {
      const container = scrollContainerRef.current;
      if (!container) return;

      const speed = autoScrollSpeedRef.current;
      if (speed === 0) {
        autoScrollRAFRef.current = null;
        return;
      }

      container.scrollTop += speed;
      autoScrollRAFRef.current = requestAnimationFrame(tick);
    };

    autoScrollRAFRef.current = requestAnimationFrame(tick);
  }, [scrollContainerRef]);

  const scheduleEdgeNav = useCallback(
    (direction: number) => {
      if (edgeNavDirectionRef.current === direction) return;

      cancelEdgeNav();
      edgeNavDirectionRef.current = direction;

      const fireNav = () => {
        onDragNavigateRef.current?.(direction);
        edgeNavTimerRef.current = setTimeout(fireNav, EDGE_NAV_REPEAT_MS);
      };

      edgeNavTimerRef.current = setTimeout(fireNav, EDGE_NAV_DELAY_MS);
    },
    [cancelEdgeNav],
  );

  // Initialize the handlers once (stable references via refs)
  useEffect(() => {
    handleMouseMoveRef.current = (e: MouseEvent) => {
      const drag = dragRef.current;
      if (!drag) return;

      const deltaY = Math.abs(e.clientY - drag.startClientY);
      const deltaX = Math.abs(e.clientX - drag.startClientX);
      if (
        !drag.isDragging &&
        deltaY < DRAG_THRESHOLD_PX &&
        deltaX < DRAG_THRESHOLD_PX
      )
        return;

      if (!drag.isDragging) {
        drag.isDragging = true;
      }

      const container = scrollContainerRef.current;
      if (!container) return;

      const containerRect = container.getBoundingClientRect();
      const scrollTop = container.scrollTop;
      const absoluteY =
        e.clientY - containerRect.top + scrollTop - drag.offsetWithinEvent;
      const absoluteX =
        e.clientX - containerRect.left - drag.offsetWithinEventX;
      const rawMinutes = (absoluteY / hourHeightRef.current) * 60;
      const snappedStartMinutes = snapToGrid(rawMinutes);
      const clampedStart = Math.max(
        0,
        Math.min(snappedStartMinutes, 1440 - drag.durationMinutes),
      );

      // Column detection — based on raw cursor position over the grid
      const colWidth = dayColumnWidthRef.current;
      const visibleDays = daysRef.current;
      const gridLeftEdge = containerRect.left + timeAxisWidthRef.current;
      const cursorInGrid = e.clientX - gridLeftEdge;
      const columnIndex = clamp(
        Math.floor(cursorInGrid / colWidth),
        0,
        visibleDays.length - 1,
      );
      const targetDay = visibleDays[columnIndex];

      const currentStart = addMinutesToDate(targetDay, clampedStart);
      const currentEnd = addMinutesToDate(
        targetDay,
        clampedStart + drag.durationMinutes,
      );

      setDragState({
        eventId: drag.eventId,
        event: drag.event,
        originalStart: drag.event.start,
        originalEnd: drag.event.end,
        currentStart,
        currentEnd,
        currentDate: targetDay,
        isDragging: true,
        cursorY: absoluteY,
        cursorX: absoluteX,
        clientX: e.clientX - drag.offsetWithinEventX,
        clientY: e.clientY - drag.offsetWithinEvent,
      });

      // Edge-of-view week navigation
      // Trigger when cursor is within EDGE_ZONE_PX of the grid boundary OR past it
      const cursorXInGrid = e.clientX - gridLeftEdge;
      const gridWidth = colWidth * visibleDays.length;

      if (cursorXInGrid < EDGE_ZONE_PX) {
        scheduleEdgeNav(-7);
      } else if (cursorXInGrid > gridWidth - EDGE_ZONE_PX) {
        scheduleEdgeNav(7);
      } else {
        cancelEdgeNav();
      }

      // Auto-scroll at top/bottom edges
      const cursorYInContainer = e.clientY - containerRect.top;
      const containerHeight = containerRect.height;

      if (cursorYInContainer < AUTO_SCROLL_ZONE_PX) {
        const dist = cursorYInContainer;
        autoScrollSpeedRef.current =
          -AUTO_SCROLL_MAX_SPEED * (1 - dist / AUTO_SCROLL_ZONE_PX);
        startAutoScrollLoop();
      } else if (cursorYInContainer > containerHeight - AUTO_SCROLL_ZONE_PX) {
        const dist = containerHeight - cursorYInContainer;
        autoScrollSpeedRef.current =
          AUTO_SCROLL_MAX_SPEED * (1 - dist / AUTO_SCROLL_ZONE_PX);
        startAutoScrollLoop();
      } else {
        cancelAutoScroll();
      }
    };

    handleMouseUpRef.current = () => {
      const drag = dragRef.current;
      if (!drag) return;

      cleanup();

      if (drag.isDragging) {
        setDragState((prev) => {
          if (!prev) return null;

          const event = eventsRef.current.find((e) => e.id === drag.eventId);
          if (!event) return null;

          onEventChangeRef.current?.({
            ...event,
            start: prev.currentStart,
            end: prev.currentEnd,
          });

          return null;
        });
      } else {
        setDragState(null);
      }

      dragRef.current = null;
    };
  }, [
    scrollContainerRef,
    cleanup,
    scheduleEdgeNav,
    cancelEdgeNav,
    cancelAutoScroll,
    startAutoScrollLoop,
  ]);

  const handleEventMouseDown = useCallback(
    (e: React.MouseEvent, event: CalendarEvent) => {
      if (e.button !== 0) return;

      // Select the event immediately
      onEventClickRef.current?.(event);

      const container = scrollContainerRef.current;
      if (!container) return;

      // Compute offset within the event element
      const target = e.currentTarget as HTMLElement;
      const targetRect = target.getBoundingClientRect();
      const offsetWithinEvent = e.clientY - targetRect.top;
      const offsetWithinEventX = e.clientX - targetRect.left;

      const startMinutes =
        event.start.getHours() * 60 + event.start.getMinutes();
      const endMinutes = event.end.getHours() * 60 + event.end.getMinutes();
      const durationMinutes = endMinutes - startMinutes;

      dragRef.current = {
        eventId: event.id,
        event,
        startClientY: e.clientY,
        startClientX: e.clientX,
        offsetWithinEvent,
        offsetWithinEventX,
        isDragging: false,
        durationMinutes,
      };

      setDragState({
        eventId: event.id,
        event,
        originalStart: event.start,
        originalEnd: event.end,
        currentStart: event.start,
        currentEnd: event.end,
        currentDate: event.start,
        isDragging: false,
        cursorY: 0,
        cursorX: 0,
        clientX: 0,
        clientY: 0,
      });

      if (handleMouseMoveRef.current) {
        window.addEventListener("mousemove", handleMouseMoveRef.current);
      }
      if (handleMouseUpRef.current) {
        window.addEventListener("mouseup", handleMouseUpRef.current);
      }
    },
    [scrollContainerRef],
  );

  // Cleanup on unmount
  useEffect(() => {
    return cleanup;
  }, [cleanup]);

  return { dragState, handleEventMouseDown };
}

