        // Same-day: enforce min duration
        if (isSameDay(startDate, endDate)) {
          newEndMinutes = clamp(
            newEndMinutes,
            anchorMinutes + MIN_DURATION_MINUTES,
            1440,
          );
        }
      } else if (cursorTimestamp < anchorTimestamp) {
        // Cursor is before anchor → effective top
        effectiveEdge = "top";
        endDate = anchorDate;
        newEndMinutes = anchorMinutes;
        startDate = targetDay;
        newStartMinutes = clamp(snappedMinutes, 0, 1440);

        // Cross-day edge case: cursor at minute 1440 on day right before anchor → treat as start-of-anchor-day
        if (!isSameDay(targetDay, anchorDate)) {
          const dayBeforeAnchor = new Date(anchorDate);
          dayBeforeAnchor.setDate(dayBeforeAnchor.getDate() - 1);
          dayBeforeAnchor.setHours(0, 0, 0, 0);

          if (isSameDay(targetDay, dayBeforeAnchor) && snappedMinutes >= 1440) {
            newStartMinutes = 0;
            startDate = anchorDate;
          }
        }

        // Same-day: enforce min duration
        if (isSameDay(startDate, endDate)) {
          newStartMinutes = clamp(
            newStartMinutes,
            0,
            anchorMinutes - MIN_DURATION_MINUTES,
          );
        }
      } else {
        // Cursor at anchor → keep minimum duration in original edge direction (no flip)
        effectiveEdge = resize.edge;
        if (resize.edge === "bottom") {
          startDate = anchorDate;
          newStartMinutes = anchorMinutes;
          endDate = anchorDate;
          newEndMinutes = anchorMinutes + MIN_DURATION_MINUTES;
        } else {
          endDate = anchorDate;
          newEndMinutes = anchorMinutes;
          startDate = anchorDate;
          newStartMinutes = anchorMinutes - MIN_DURATION_MINUTES;
        }
      }

      const currentStart = addMinutesToDate(startDate, newStartMinutes);
      const currentEnd = addMinutesToDate(endDate, newEndMinutes);

      setResizeState({
        eventId: resize.eventId,
        event: resize.event,
        originalStart: resize.event.start,
        originalEnd: resize.event.end,
        currentStart,
        currentEnd,
        edge: resize.edge,
        effectiveEdge,
        isResizing: true,
        currentEndDate: endDate,
        currentStartDate: startDate,
      });

      // Auto-scroll at top/bottom edges
      const cursorYInContainer = e.clientY - containerRect.top;
      const containerHeight = containerRect.height;

      if (cursorYInContainer < AUTO_SCROLL_ZONE_PX) {
        const dist = cursorYInContainer;
        autoScrollSpeedRef.current =
          -AUTO_SCROLL_MAX_SPEED * (1 - dist / AUTO_SCROLL_ZONE_PX);
        startAutoScrollLoop();
      } else if (cursorYInContainer > containerHeight - AUTO_SCROLL_ZONE_PX) {
        const dist = containerHeight - cursorYInContainer;
        autoScrollSpeedRef.current =
          AUTO_SCROLL_MAX_SPEED * (1 - dist / AUTO_SCROLL_ZONE_PX);
        startAutoScrollLoop();
      } else {
        cancelAutoScroll();
      }

      // Edge-of-view week navigation
      const cursorXInGrid = e.clientX - gridLeftEdge;
      const gridWidth = colWidth * visibleDays.length;

      if (cursorXInGrid < EDGE_ZONE_PX) {
        scheduleEdgeNav(-7);
      } else if (cursorXInGrid > gridWidth - EDGE_ZONE_PX) {
        scheduleEdgeNav(7);
      } else {
        cancelEdgeNav();
      }
    };

    handleMouseUpRef.current = () => {
      const resize = resizeRef.current;
      if (!resize) return;

      cleanup();

      if (resize.isResizing) {
        setResizeState((prev) => {
          if (!prev) return null;

          const event = eventsRef.current.find((e) => e.id === resize.eventId);
          if (!event) return null;

          const MS_IN_24H = 24 * 60 * 60 * 1000;
          const isLongerThan24h =
            prev.currentEnd.getTime() - prev.currentStart.getTime() > MS_IN_24H;

          onEventChangeRef.current?.({
            ...event,
            start: prev.currentStart,
            end: prev.currentEnd,
            isAllDay: isLongerThan24h,
          });

          return null;
        });
      } else {
        setResizeState(null);
      }

      resizeRef.current = null;
    };
  }, [
    scrollContainerRef,
    cleanup,
    cancelAutoScroll,
    startAutoScrollLoop,
    scheduleEdgeNav,
    cancelEdgeNav,
  ]);

  const handleResizeMouseDown = useCallback(
    (e: React.MouseEvent, event: CalendarEvent, edge: "top" | "bottom") => {
      if (e.button !== 0) return;

      e.stopPropagation();

      onEventClickRef.current?.(event);

      const originalStartMinutes =
        event.start.getHours() * 60 + event.start.getMinutes();
      const originalEndMinutes =
        event.end.getHours() * 60 + event.end.getMinutes();

      const originalStartDate = startOfDay(event.start);
      const originalEndDate = startOfDay(event.end);

      resizeRef.current = {
        eventId: event.id,
        event,
        edge,
        startClientY: e.clientY,
        isResizing: false,
        originalStartMinutes,
        originalEndMinutes,
        originalStartDate,
        originalEndDate,
      };

      setResizeState({
        eventId: event.id,
        event,
        originalStart: event.start,
        originalEnd: event.end,
        currentStart: event.start,
        currentEnd: event.end,
        edge,
        effectiveEdge: edge,
        isResizing: false,
        currentEndDate: originalEndDate,
        currentStartDate: originalStartDate,
      });

      if (handleMouseMoveRef.current) {
        window.addEventListener("mousemove", handleMouseMoveRef.current);
      }
      if (handleMouseUpRef.current) {
        window.addEventListener("mouseup", handleMouseUpRef.current);
      }
    },
    [],
  );

  useEffect(() => {
    return cleanup;
  }, [cleanup]);

  return { resizeState, handleResizeMouseDown };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

interface UseHorizontalScrollOptions {
  containerRef: React.RefObject<HTMLDivElement | null>;
  dayColumnWidth: number;
  onNavigate: (daysDelta: number) => void;
  disabled?: boolean;
}

interface UseHorizontalScrollReturn {
  scrollOffset: number;
  slideOffset: number;
  isScrolling: boolean;
  isAnimating: boolean;
  triggerSlideAnimation: (daysDelta: number) => void;
}

const SCROLL_END_DEBOUNCE_MS = 150;
const SNAP_ANIMATION_MS = 200;

export function useHorizontalScroll({
  containerRef,
  dayColumnWidth,
  onNavigate,
  disabled,
}: UseHorizontalScrollOptions): UseHorizontalScrollReturn {
  const [scrollOffset, setScrollOffset] = useState(0);
  const [slideOffset, setSlideOffset] = useState(0);
  const [isScrolling, setIsScrolling] = useState(false);
  const [isAnimating, setIsAnimating] = useState(false);

  const scrollEndTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const accumulatedDelta = useRef(0);
  const onNavigateRef = useRef(onNavigate);
  useEffect(() => {
    onNavigateRef.current = onNavigate;
  }, [onNavigate]);

  const snapAndNavigate = useCallback(
    (offset: number) => {
      if (dayColumnWidth <= 0) return;

      const daysDelta = Math.round(offset / dayColumnWidth);

      // If scroll distance < half a day-column width, snap back
      if (daysDelta === 0) {
        setIsAnimating(true);
        setScrollOffset(0);
        setTimeout(() => {
          setIsAnimating(false);
          setIsScrolling(false);
        }, SNAP_ANIMATION_MS);
        return;
      }

      // Snap to exact day boundary then navigate
      const targetOffset = daysDelta * dayColumnWidth;
      setIsAnimating(true);
      setScrollOffset(targetOffset);

      setTimeout(() => {
        onNavigateRef.current(-daysDelta);
        setScrollOffset(0);
        setIsAnimating(false);
        setIsScrolling(false);
        accumulatedDelta.current = 0;
      }, SNAP_ANIMATION_MS);
    },
    [dayColumnWidth],
  );

  // Programmatic slide animation for button/keyboard navigation
  // Uses slideOffset (not scrollOffset) so dynamicBuffer isn't affected
  // Does NOT call onNavigate — caller is responsible for having already changed the date
  const triggerSlideAnimation = useCallback(
    (daysDelta: number) => {
      if (dayColumnWidth <= 0 || isAnimating || isScrolling) return;

      // Start from the opposite direction to create slide effect
      const startOffset = daysDelta * dayColumnWidth;
      setSlideOffset(startOffset);

      // Force a reflow then animate to 0
      requestAnimationFrame(() => {
        requestAnimationFrame(() => {
          setIsAnimating(true);
          setSlideOffset(0);
          setTimeout(() => {
            setIsAnimating(false);
          }, SNAP_ANIMATION_MS);
        });
      });
    },
    [dayColumnWidth, isAnimating, isScrolling],
  );

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const handleWheel = (e: WheelEvent) => {
      if (disabled) return;

      // Only handle horizontal-dominant scrolls
      if (Math.abs(e.deltaX) <= Math.abs(e.deltaY)) return;

      e.preventDefault();

      setIsScrolling(true);

      // Negate deltaX: scroll right (positive deltaX) = move calendar left = navigate forward
      accumulatedDelta.current += -e.deltaX;
      setScrollOffset(accumulatedDelta.current);

      // Reset debounce timer
      if (scrollEndTimer.current) {
        clearTimeout(scrollEndTimer.current);
      }

      scrollEndTimer.current = setTimeout(() => {
        snapAndNavigate(accumulatedDelta.current);
        accumulatedDelta.current = 0;
      }, SCROLL_END_DEBOUNCE_MS);
    };

    container.addEventListener("wheel", handleWheel, { passive: false });

    return () => {
      container.removeEventListener("wheel", handleWheel);
      if (scrollEndTimer.current) {
        clearTimeout(scrollEndTimer.current);
      }
    };
  }, [containerRef, snapAndNavigate, disabled]);

  return {
    scrollOffset,
    slideOffset,
    isScrolling,
    isAnimating,
    triggerSlideAnimation,
  };
}

import * as React from "react";

const MOBILE_BREAKPOINT = 768;

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(
    undefined,
  );

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`);
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    };
    mql.addEventListener("change", onChange);
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT);
    return () => mql.removeEventListener("change", onChange);
  }, []);

  return !!isMobile;
}

import {
  isSameDay,
  startOfDay,
  addDays,
  differenceInMinutes,
  isWithinInterval,
  areIntervalsOverlapping,
} from "date-fns";
import type {
  CalendarEvent,
  PositionedEvent,
  WeekDay,
} from "@/components/layouts/calendar/week-view-types";

/** Returns true when a timed event spans across midnight into a different day. */
export function isMultiDayEvent(event: CalendarEvent): boolean {
  if (event.isAllDay) {
    return false;
  }
  return !isSameDay(event.start, event.end);
}

/**
 * Filters events for a specific day (excluding all-day and multi-day events)
 */
export function getEventsForDay(
  events: CalendarEvent[],
  day: WeekDay,
): CalendarEvent[] {
  const dayStart = startOfDay(day.date);
  const dayEnd = addDays(dayStart, 1);

  return events.filter((event) => {
    if (event.isAllDay || isMultiDayEvent(event)) {
      return false;
    }
    // Event spans this day if it starts before day end AND ends after day start
    return event.start < dayEnd && event.end > dayStart;
  });
}

/**
 * Gets all-day events that span a specific day
 */
export function getAllDayEventsForDay(
  events: CalendarEvent[],
  day: WeekDay,
): CalendarEvent[] {
  return events.filter((event) => {
    if (!event.isAllDay) {
      return false;
    }
    const dayStart = startOfDay(day.date);
    const dayEnd = new Date(dayStart);
    dayEnd.setHours(23, 59, 59, 999);

    return (
      isWithinInterval(dayStart, { start: event.start, end: event.end }) ||
      isSameDay(event.start, day.date) ||
      isSameDay(event.end, day.date)
    );
  });
}

/**
 * Checks if two events overlap in time
 */
function eventsOverlap(a: CalendarEvent, b: CalendarEvent): boolean {
  return areIntervalsOverlapping(
    { start: a.start, end: a.end },
    { start: b.start, end: b.end },
  );
}

/**
 * Groups overlapping events into columns
 */
function assignColumns(
  events: CalendarEvent[],
): Map<string, { column: number; totalColumns: number }> {
  const columnAssignments = new Map<
    string,
    { column: number; totalColumns: number }
  >();

  if (events.length === 0) {
    return columnAssignments;
  }

  // Sort events by start time, then by duration (longer first)
  const sortedEvents = [...events].sort((a, b) => {
    const startDiff = a.start.getTime() - b.start.getTime();
    if (startDiff !== 0) {
      return startDiff;
    }
    // Longer events first
    const durationA = a.end.getTime() - a.start.getTime();
    const durationB = b.end.getTime() - b.start.getTime();
    return durationB - durationA;
  });

  // Find groups of overlapping events
  const groups: CalendarEvent[][] = [];
  const processed = new Set<string>();

  for (const event of sortedEvents) {
    if (processed.has(event.id)) {
      continue;
    }

    const group: CalendarEvent[] = [event];
    processed.add(event.id);

    // Find all events that overlap with any event in the group
    let foundNew = true;
    while (foundNew) {
      foundNew = false;
      for (const otherEvent of sortedEvents) {
        if (processed.has(otherEvent.id)) {
          continue;
        }
        const overlapsWithGroup = group.some((groupEvent) =>
          eventsOverlap(groupEvent, otherEvent),
        );
        if (!overlapsWithGroup) {
          continue;
        }
        group.push(otherEvent);
        processed.add(otherEvent.id);
        foundNew = true;
      }
    }

    groups.push(group);
  }

  // Assign columns within each group
  for (const group of groups) {
    const columns: CalendarEvent[][] = [];

    // Sort group by start time
    group.sort((a, b) => a.start.getTime() - b.start.getTime());

    for (const event of group) {
      // Find the first column where this event doesn't overlap with existing events
      let placed = false;
      for (let colIndex = 0; colIndex < columns.length; colIndex++) {
        const column = columns[colIndex];
        const overlapsWithColumn = column.some((colEvent) =>
          eventsOverlap(colEvent, event),
        );
        if (overlapsWithColumn) {
          continue;
        }
        column.push(event);
        columnAssignments.set(event.id, { column: colIndex, totalColumns: 0 });
        placed = true;
        break;
      }

      if (placed) {
        continue;
      }

      // Create new column
      columns.push([event]);
      columnAssignments.set(event.id, {
        column: columns.length - 1,
        totalColumns: 0,
      });
    }

    // Update total columns for all events in group
    const totalColumns = columns.length;
    for (const event of group) {
      const assignment = columnAssignments.get(event.id);
      if (!assignment) {
        continue;
      }
      assignment.totalColumns = totalColumns;
    }
  }

  return columnAssignments;
}

/**
 * Calculates positioned events for rendering in the grid.
 * @param rightGapPercent - right gap in percentage. Defaults to 8.
 *   Pass 0 for day view so events fill the full column width.
 */
export function calculatePositionedEvents(
  events: CalendarEvent[],
  day: WeekDay,
  rightGapPercent = 8,
): PositionedEvent[] {
  const dayEvents = getEventsForDay(events, day);

  if (dayEvents.length === 0) {
    return [];
  }

  const columnAssignments = assignColumns(dayEvents);
  const dayStart = startOfDay(day.date);

  const nextDayMidnight = addDays(dayStart, 1);

  return dayEvents.map((event) => {
    const assignment = columnAssignments.get(event.id) ?? {
      column: 0,
      totalColumns: 1,
    };

    // Compute effective start/end clamped to this day's boundaries
    const effectiveStart = event.start > dayStart ? event.start : dayStart;
    const effectiveEnd =
      event.end < nextDayMidnight ? event.end : nextDayMidnight;

    // Calculate top position (percentage from day start)
    const minutesFromDayStart = differenceInMinutes(effectiveStart, dayStart);
    const top = (minutesFromDayStart / (24 * 60)) * 100;

    // Calculate height (percentage of the day)
    const durationMinutes = differenceInMinutes(effectiveEnd, effectiveStart);
    const height = (durationMinutes / (24 * 60)) * 100;

    // Determine segment position for multi-day events
    const startsOnDay = isSameDay(event.start, dayStart);
    const endsOnDay = event.end <= nextDayMidnight;
    let segmentPosition: "start" | "middle" | "end" | "full" = "full";
    if (startsOnDay && !endsOnDay) {
      segmentPosition = "start";
    } else if (!startsOnDay && endsOnDay) {
      segmentPosition = "end";
    } else if (!startsOnDay && !endsOnDay) {
      segmentPosition = "middle";
    }

    // Calculate left and width based on column assignment
    // Events cascade with overlap - leftmost event has no gap, rightmost has gap
    const rightGap = rightGapPercent;
    const overlapAmount = 8; // percentage overlap between adjacent events
    const { column, totalColumns } = assignment;

    let left: number;
    let width: number;

    if (totalColumns === 1) {
      // Single event: full width with right gap
      left = 0;
      width = 100 - rightGap;
    } else {
      // Multiple overlapping events
      // Formula: n * eventWidth - (n-1) * overlap = availableWidth
      // So: eventWidth = (availableWidth + (n-1) * overlap) / n
      const eventWidth =
        (100 - rightGap + overlapAmount * (totalColumns - 1)) / totalColumns;

      left = column * (eventWidth - overlapAmount);

      if (column === totalColumns - 1) {
        // Last event: fill to end (has the right gap)
        width = 100 - rightGap - left;
      } else {
        // Other events extend under the next one (no gap)
        width = eventWidth;
      }
    }

    return {
      event,
      top,
      height,
      left,
      width,
      column: assignment.column,
      totalColumns: assignment.totalColumns,
      segmentPosition,
    };
  });
}

/**
 * Groups all-day events by their visual row (for stacking)
 */
export interface AllDayEventRow {
  event: CalendarEvent;
  startColumn: number;
  endColumn: number;
  row: number;
}

export function calculateAllDayEventRows(
  events: CalendarEvent[],
  days: WeekDay[],
): AllDayEventRow[] {
  const allDayEvents = events.filter((e) => e.isAllDay || isMultiDayEvent(e));

  if (allDayEvents.length === 0) {
    return [];
  }

  // Sort by start date, then by duration (longer first)
  const sortedEvents = [...allDayEvents].sort((a, b) => {
    const startDiff = a.start.getTime() - b.start.getTime();
    if (startDiff !== 0) {
      return startDiff;
    }
    const durationA = a.end.getTime() - a.start.getTime();
    const durationB = b.end.getTime() - b.start.getTime();
    return durationB - durationA;
  });

  const rows: AllDayEventRow[] = [];
  const occupiedRows: Map<number, { start: number; end: number }[]> = new Map();

  for (const event of sortedEvents) {
    // Find start and end columns
    let startColumn = -1;
    let endColumn = -1;

    for (let i = 0; i < days.length; i++) {
      const day = days[i];
      const dayStart = startOfDay(day.date);

      if (
        isSameDay(event.start, day.date) ||
        (event.start <= dayStart && event.end >= dayStart)
      ) {
        if (startColumn === -1) {
          startColumn = i;
        }
        endColumn = i;
      }
    }

    if (startColumn === -1) {
      continue;
    }

    // Find the first row where this event fits
    let targetRow = 0;
    let foundRow = false;

    while (!foundRow) {
      const rowOccupied = occupiedRows.get(targetRow) ?? [];
      const hasConflict = rowOccupied.some(
        (occupied) =>
          !(endColumn < occupied.start || startColumn > occupied.end),
      );

      if (!hasConflict) {
        foundRow = true;
        break;
      }

      targetRow++;
    }

    // Mark the row as occupied
    const rowOccupied = occupiedRows.get(targetRow) ?? [];
    rowOccupied.push({ start: startColumn, end: endColumn });
    occupiedRows.set(targetRow, rowOccupied);

    rows.push({
      event,
      startColumn,
      endColumn,
      row: targetRow,
    });
  }

  return rows;
}

"use client";

import * as React from "react";
import Link from "next/link";
import {
  ArrowLeftIcon,
  ChevronLeftIcon,
  ChevronRightIcon,
